#include <iostream>
#include <string>

#define ROWS 3
#define COLS 3

bool areMatricesEqual(int mat1[ROWS][COLS], int mat2[ROWS][COLS], int rows, int cols) {
    if (rows < 0 || cols < 0) {
        std::cerr << "Error: Matrix dimensions cannot be negative (rows=" << rows << ", cols=" << cols << ")." << std::endl;
        return false;
    }
    if (rows > ROWS || cols > COLS) {
        std::cerr << "Error: Comparison dimensions (" << rows << "x" << cols << ") exceed declared matrix capacity (" << ROWS << "x" << COLS << ")." << std::endl;
        return false;
    }
    if (rows == 0 || cols == 0) {
        return true;
    }
    for (int i = 0; i < rows; ++i) {
        for (int j = 0; j < cols; ++j) {
            if (mat1[i][j] != mat2[i][j]) {
                return false;
            }
        }
    }
    return true;
}

void printMatrix(int mat[ROWS][COLS], int r, int c) {
    if (r <= 0 || c <= 0) {
        std::cout << "[Empty Matrix]" << std::endl;
        return;
    }
    for (int i = 0; i < r; ++i) {
        for (int j = 0; j < c; ++j) {
            std::cout << mat[i][j] << (j == c - 1 ? "" : " ");
        }
        std::cout << std::endl;
    }
}

int main() {
    int matrixA[ROWS][COLS] = {
        {1, 2, 3},
        {4, 5, 6},
        {7, 8, 9}
    };
    int matrixB[ROWS][COLS] = {
        {1, 2, 3},
        {4, 5, 6},
        {7, 8, 9}
    };
    int matrixC[ROWS][COLS] = {
        {1, 2, 3},
        {4, 0, 6},
        {7, 8, 9}
    };

    std::cout << "Test Case 1 (A vs B, 3x3): " << (areMatricesEqual(matrixA, matrixB, 3, 3) ? "Equal" : "Not Equal") << std::endl;
    std::cout << "Test Case 2 (A vs C, 3x3): " << (areMatricesEqual(matrixA, matrixC, 3, 3) ? "Equal" : "Not Equal") << std::endl;
    std::cout << "Test Case 3 (A vs B, 2x2): " << (areMatricesEqual(matrixA, matrixB, 2, 2) ? "Equal" : "Not Equal") << std::endl;
    std::cout << "Test Case 4 (A vs B, 0x0): " << (areMatricesEqual(matrixA, matrixB, 0, 0) ? "Equal" : "Not Equal") << std::endl;
    std::cout << "Test Case 5 (A vs B, -1x3): " << (areMatricesEqual(matrixA, matrixB, -1, 3) ? "Equal" : "Not Equal") << std::endl;
    std::cout << "Test Case 6 (A vs B, 4x3 - OOB rows): " << (areMatricesEqual(matrixA, matrixB, 4, 3) ? "Equal" : "Not Equal") << std::endl;
    std::cout << "Test Case 7 (A vs C, 3x4 - OOB cols): " << (areMatricesEqual(matrixA, matrixC, 3, 4) ? "Equal" : "Not Equal") << std::endl;

    return 0;
}
